test.code:
def test_fallback_context_reference():
    engine = FallbackEngine(test_config)
    payload = engine.generate("scaffold", "所以变量就像盒子", {
        "turn": 1, "prev_user": "变量是什么",
    })
    stmt = payload.get("statement", "")
    assert "你说得对" in stmt or "是的" in stmt

def test_fallback_no_empty_responses():
    engine = FallbackEngine(test_config)
    for at in ["scaffold", "suggest", "reflect", "challenge", "probe"]:
        payload = engine.generate(at, "python 学习")
        assert payload.get("statement", ""), f"{at} returned empty statement"
        assert payload.get("question", ""), f"{at} returned empty question"
